-- ==========================================
-- 1. LOOKUP TABLES
-- ==========================================

-- Using singular: MANUFACTURER
CREATE TABLE MANUFACTURER (
    MANUFACTURER_ID INT IDENTITY(1,1) PRIMARY KEY,
    MANUFACTURER_NAME NVARCHAR(100) NOT NULL
);


-- Using singular: PC_MODEL
CREATE TABLE PC_MODEL (
    MODEL_ID        INT IDENTITY(1,1) PRIMARY KEY,
    MANUFACTURER_ID INT NOT NULL,
    MODEL_NAME      NVARCHAR(100) NOT NULL,
    CONSTRAINT FK_PC_MODEL_MANUFACTURER FOREIGN KEY (MANUFACTURER_ID) 
        REFERENCES MANUFACTURER(MANUFACTURER_ID)
);





-- Using singular: DEVICE_TYPE
CREATE TABLE DEVICE_TYPE (
    DEVICE_TYPE_ID INT IDENTITY(1,1) PRIMARY KEY,
    DEVICE_TYPE_NAME NVARCHAR(50) NOT NULL
);

-- Inserts without specifying DEVICE_TYPE_ID (auto-generated)


-- Using singular: OPERATING_SYSTEM
CREATE TABLE OPERATING_SYSTEM (
    OS_ID   INT IDENTITY(1,1) PRIMARY KEY,
    OS_NAME NVARCHAR(100) NOT NULL
);

-- Inserts without specifying OS_ID (auto-generated)


-- Using singular: CPU
-- =========================================
-- TABLE: CPU
-- =========================================
CREATE TABLE CPU (
    CPU_ID INT IDENTITY(1,1) PRIMARY KEY,
    CPU_MANUFACTURER NVARCHAR(50),
    CPU_GENERATION NVARCHAR(50),
    CPU_MODEL NVARCHAR(100)
);




CREATE TABLE LOCATION (
    LOCATION_ID INT IDENTITY(1,1) PRIMARY KEY,
    BRANCH      NVARCHAR(50),
    FLOOR_NO    NVARCHAR(50),
    ROOM_NAME   NVARCHAR(100)
);



CREATE TABLE OFFICE_SOFTWARE (
    OFFICE_ID    INT IDENTITY(1,1) PRIMARY KEY,
    OFFICE_SOFTWARE_NAME NVARCHAR(100) NOT NULL
);




CREATE TABLE SECURITY_SOFTWARE (
    SECURITY_ID   INT IDENTITY(1,1) PRIMARY KEY,
    SECURITY_SOFTWARE_NAME NVARCHAR(100) NOT NULL
);



-- 8. EMPLOYEE
CREATE TABLE EMPLOYEE_USER (
    EMPLOYEE_ID    INT IDENTITY(1,1) PRIMARY KEY,
    EMPLOYEE_NAME  NVARCHAR(100) NOT NULL
);



-- 9. DISPOSAL_FLAG
CREATE TABLE DISPOSAL_FLAG (
    FLAG_ID    INT IDENTITY(1,1) PRIMARY KEY,
    FLAG_DESC  NVARCHAR(100)
);


-- 10. WIN10UPDATE_FLAG
CREATE TABLE WIN10UPDATE_FLAG (
    FLAG_ID    INT IDENTITY(1,1) PRIMARY KEY,
    FLAG_DESC  NVARCHAR(50)
);


-- 11. ADMINS(SYSTEM LOGIN)
CREATE TABLE ADMINS (
    ID INT IDENTITY(1,1) PRIMARY KEY,
    USERNAME NVARCHAR(50) NOT NULL UNIQUE,
    PASSWORD NVARCHAR(255) NOT NULL,       -- Long enough for BCRYPT hashes
    ROLE NVARCHAR(20) DEFAULT 'ROLE_ADMIN',-- "ROLE_" prefix expected by Spring Security
    ENABLED BIT DEFAULT 1                  -- 1 = ACTIVE, 0 = LOCKED
);

