-- 12. PROJECTS
CREATE TABLE PROJECT (
    PROJECT_ID INT IDENTITY(1,1) PRIMARY KEY,
    PROJECT_NAME NVARCHAR(100)
);



-- 13. Monitors 
CREATE TABLE MONITOR (
    MONITOR_ID INT IDENTITY(1,1) PRIMARY KEY,
    MONITOR_NAME NVARCHAR(100)
);



-- 14. MemoryRam 
CREATE TABLE MEMORYRAM (
    MEMORY_ID    NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    MEMORY_SPEC  NVARCHAR(100)
);

-- 15. Company 
CREATE TABLE COMPANY (
    COMPANY_ID    NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    COMPANY_NAME  NVARCHAR(100)
);

-- 16. Holding 
CREATE TABLE HOLDING (
    HOLDING_ID    NUMBER GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    HOLDING_NAME  NVARCHAR(100)
);



-- ==========================================
-- 2. MAIN ASSET TABLE
-- ==========================================

CREATE TABLE PC_ASSET (
    ASSET_ID           INT IDENTITY(1,1) PRIMARY KEY,
    COMPUTER_NAME      NVARCHAR(100) NOT NULL,
    MODEL_ID           INT DEFAULT 1,
    DEVICE_TYPE_ID     INT DEFAULT 1,
    CPU_ID             INT DEFAULT 1,
    MAC_ADDRESS        NVARCHAR(17) UNIQUE,
    RAM_MB             INT,

    DOMAIN             INT DEFAULT 1,
    HOLDING            INT DEFAULT 1,
    
    OS_ID              INT DEFAULT 1,
    OFFICE_ID          INT DEFAULT 1,
    SECURITY_ID        INT DEFAULT 1,
    PURCHASE_DATE      DATE,
    
    DISPLAY_MAKER      INT DEFAULT 1,
    HAS_KEYBOARD       BIT DEFAULT 0,   -- 0/1 instead of NUMBER(1) with CHECK
    HAS_MOUSE          BIT DEFAULT 0,
    OTHER_PERIPHERALS  NVARCHAR(MAX),    -- CLOB equivalent in SQL Server
    
    LOCATION_ID        INT DEFAULT 1,
    ASSIGNED_EMPLOYEE_ID INT DEFAULT 1,
    PROJECT_ID         INT DEFAULT 1,
    WIN10_STATUS       INT DEFAULT 1,
    REMARKS            NVARCHAR(MAX),
    
    DISPOSAL_FLAG      INT DEFAULT 0,
    DISPOSAL_STATUS    INT DEFAULT 1,
    STATUS_CHANGE_DATE DATE,
    EXISTCURRENT       BIT DEFAULT 1,
    CREATED_AT         DATETIME2 DEFAULT SYSUTCDATETIME(), -- Oracle CURRENT_TIMESTAMP equivalent
    UPDATED_AT         DATETIME2, -- Will be updated by trigger

    -- FOREIGN KEYS
    CONSTRAINT FK_ASSET_MODEL    FOREIGN KEY (MODEL_ID)             REFERENCES PC_MODEL(MODEL_ID),
    CONSTRAINT FK_ASSET_TYPE     FOREIGN KEY (DEVICE_TYPE_ID)       REFERENCES DEVICE_TYPE(DEVICE_TYPE_ID),
    CONSTRAINT FK_ASSET_CPU      FOREIGN KEY (CPU_ID)               REFERENCES CPU(CPU_ID),
    CONSTRAINT FK_ASSET_OS       FOREIGN KEY (OS_ID)                REFERENCES OPERATING_SYSTEM(OS_ID),
    CONSTRAINT FK_ASSET_OFFICE   FOREIGN KEY (OFFICE_ID)            REFERENCES OFFICE_SOFTWARE(OFFICE_ID),
    CONSTRAINT FK_ASSET_SECURITY FOREIGN KEY (SECURITY_ID)          REFERENCES SECURITY_SOFTWARE(SECURITY_ID),
    CONSTRAINT FK_ASSET_LOCATION FOREIGN KEY (LOCATION_ID)          REFERENCES LOCATION(LOCATION_ID),
    CONSTRAINT FK_ASSET_EMPLOYEE FOREIGN KEY (ASSIGNED_EMPLOYEE_ID) REFERENCES EMPLOYEE_USER(EMPLOYEE_ID),
    CONSTRAINT FK_ASSET_WIN10    FOREIGN KEY (WIN10_STATUS)         REFERENCES WIN10UPDATE_FLAG(FLAG_ID),
    CONSTRAINT FK_ASSET_DISPOSAL FOREIGN KEY (DISPOSAL_STATUS)      REFERENCES DISPOSAL_FLAG(FLAG_ID),
    CONSTRAINT FK_ASSET_PROJECT  FOREIGN KEY (PROJECT_ID)           REFERENCES PROJECT(PROJECT_ID),
    CONSTRAINT FK_ASSET_DISPLAY  FOREIGN KEY (DISPLAY_MAKER)        REFERENCES MONITOR(MONITOR_ID),
    CONSTRAINT FK_DOMAIN         FOREIGN KEY (DOMAIN)               REFERENCES COMPANY(COMPANY_ID),
    CONSTRAINT FK_HOLDING        FOREIGN KEY (HOLDING)              REFERENCES HOLDING(HOLDING_ID)
);

-- INDEXES
CREATE INDEX IDX_PC_COMPUTER_NAME ON PC_ASSET(COMPUTER_NAME);
CREATE INDEX IDX_PC_STATUS ON PC_ASSET(DISPOSAL_STATUS);

-- ==========================================
-- TRIGGER: Auto-update UPDATED_AT on any change
-- ==========================================
CREATE OR ALTER TRIGGER TRG_PC_ASSET_UPDATED_AT
ON PC_ASSET
AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;

    UPDATE PC_ASSET
    SET UPDATED_AT = SYSUTCDATETIME()
    FROM PC_ASSET AS t
    INNER JOIN inserted AS i
        ON t.ASSET_ID = i.ASSET_ID;
END;

